using System.Text.Json;
using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["featureFlags"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/feature-flags",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns only the feature flag settings.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(AppConfig["featureFlags"], new JsonSerializerOptions { WriteIndented = true });
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Returns the server's current uptime and status.")]
    public static string GetStatus()
    {
        var uptime = DateTime.UtcNow - System.Diagnostics.Process.GetCurrentProcess().StartTime.ToUniversalTime();
        return $"Server is running. Uptime: {uptime:hh\\:mm\\:ss}";
    }

    [McpServerTool, Description("Echoes the provided message, useful for connectivity testing.")]
    public static string Echo(
        [Description("The message to echo back")] string message) =>
        $"Echo: {message}";
}

